import React, { useState, useEffect } from 'react';
import API from '../utils/axios';
import { useNavigate } from 'react-router-dom';

const ProviderUpsert = () => {
  const [formData, setFormData] = useState({
    category: '',
    availability: '',
    contact: ''
  });

  const [lat, setLat] = useState(null);
  const [lng, setLng] = useState(null);

  const [token, setToken] = useState('');
  const [loading, setLoading] = useState(true);
  const [msg, setMsg] = useState('');
  const [alert, setAlert] = useState('');
  const navigate = useNavigate();

  useEffect(() => {
    setToken(localStorage.getItem('token') || '');
  }, []);

  // Get GPS location
  useEffect(() => {
    navigator.geolocation.getCurrentPosition(
      (pos) => {
        setLat(pos.coords.latitude);
        setLng(pos.coords.longitude);
      },
      (err) => {
        console.error("Location access denied", err);
      }
    );
  }, []);

  // Fetch Existing Provider Profile
  useEffect(() => {
    if (!token) return;

    const fetchProfile = async () => {
      try {
        const res = await API.get('/providers/profile', {
          headers: { Authorization: `Bearer ${token}` }
        });

        setFormData({
          category: res.data.category || '',
          availability: res.data.availability || '',
          contact: res.data.contact || ''
        });

      } catch (err) {
        console.error('❌ Error loading profile:', err.response?.data?.msg);
      } finally {
        setLoading(false);
      }
    };

    fetchProfile();
  }, [token]);

  const handleChange = e => {
    setFormData(prev => ({
      ...prev,
      [e.target.name]: e.target.value
    }));
  };

  const handleSubmit = async e => {
    e.preventDefault();
    setMsg('');

    if (!lat || !lng) {
      setMsg("Location not detected. Please enable GPS.");
      return;
    }

    try {
      await API.post('/providers/upsert',
        {
          ...formData,
          lat,
          lng
        },
        { headers: { Authorization: `Bearer ${token}` } }
      );

      setAlert('Profile saved!');
      setTimeout(() => navigate('/provider/dashboard'), 1000);

    } catch (error) {
      console.error('❌ Error saving provider:', error);
      setMsg(error.response?.data?.msg || 'Something went wrong');
    }
  };

  if (loading) return <div className="container mt-5">Loading...</div>;

  return (
    <div className="container mt-5" style={{ maxWidth: 600 }}>
      <h2 className="mb-4">Provider Profile</h2>

      {msg && <div className="alert alert-info">{msg}</div>}
      {alert && <div className="alert alert-success">{alert}</div>}

      <form onSubmit={handleSubmit}>

        {/* CATEGORY */}
        <div className="mb-3">
          <label className="form-label">Category</label>
          <select
            name="category"
            className="form-select"
            value={formData.category}
            onChange={handleChange}
            required
          >
            <option value="">Select a category</option>
            <option value="Electrician">Electrician</option>
            <option value="Plumber">Plumber</option>
            <option value="Cleaner">Cleaner</option>
            <option value="Carpenter">Carpenter</option>
            <option value="Painter">Painter</option>
            <option value="Mechanic">Mechanic</option>
          </select>
        </div>

        {/* AVAILABILITY */}
        <div className="mb-3">
          <label className="form-label">Availability</label>
          <input
            type="text"
            name="availability"
            className="form-control"
            value={formData.availability}
            onChange={handleChange}
            required
          />
        </div>

        {/* CONTACT */}
        <div className="mb-3">
          <label className="form-label">Contact</label>
          <input
            type="text"
            name="contact"
            className="form-control"
            value={formData.contact}
            onChange={handleChange}
            required
          />
        </div>

        {/* GPS STATUS */}
        <p><strong>GPS Status:</strong> {lat && lng ? "Location detected" : "Waiting for GPS..."}</p>

        <button type="submit" className="btn btn-primary w-100">Save Profile</button>
      </form>
    </div>
  );
};

export default ProviderUpsert;
